#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<pair<long long,long long>>a(n);for(auto&p:a)scanf("%lld %lld",&p.first,&p.second);sort(a.begin(),a.end());priority_queue<long long,vector<long long>,greater<long long>>pq;int best=0;for(auto&p:a){while(!pq.empty()&&pq.top()<=p.first)pq.pop();pq.push(p.second);best=max(best,(int)pq.size());}printf("%d\n",best);}
